system.radius:

  ${auth\-server1\-name}

    ${auth\-server1\-address}
    ${auth\-server1\-port}
    ${auth\-server1\-shared\-secret}

  <#if pinned\-ca\-certs1?has_content || pinned\-server\-certs1?has_content>

      <#if pinned\-ca\-certs1?has_content>
        ${pinned\-ca\-certs1}
      <#elseif pinned\-server\-certs1?has_content>
        ${pinned\-server\-certs1}
      </#if>

  </#if>

<#if auth\-server2\-name?has_content>

   ${auth\-server2\-name}

     <#if auth\-server2\-address?has_content>
     ${auth\-server2\-address}
     </#if>
     <#if auth\-server2\-port?has_content>
     ${auth\-server2\-port}
     </#if>
     <#if auth\-server2\-shared\-secret?has_content>
     ${auth\-server2\-shared\-secret}
     </#if>

  <#if auth\-server2\-address?has_content && (pinned\-ca\-certs2?has_content || pinned\-server\-certs2?has_content)>

      <#if pinned\-ca\-certs2?has_content>
        ${pinned\-ca\-certs2}
      <#elseif pinned\-server\-certs2?has_content>
        ${pinned\-server\-certs2}
      </#if>

  </#if>

</#if>
<#if acc\-server1\-name?has_content>

    ${acc\-server1\-name}

      <#if acc\-server1\-address?has_content>
      ${acc\-server1\-address}
      </#if>
      <#if acc\-server1\-port?has_content>
      ${acc\-server1\-port}
      </#if>
      <#if acc\-server1\-shared\-secret?has_content>
      ${acc\-server1\-shared\-secret}
      </#if>


</#if>
<#if acc\-server2\-name?has_content>

    ${acc\-server2\-name}

      <#if acc\-server2\-address?has_content>
      ${acc\-server2\-address}
      </#if>
      <#if acc\-server2\-port?has_content>
      ${acc\-server2\-port}
      </#if>
      <#if acc\-server2\-shared\-secret?has_content>
      ${acc\-server2\-shared\-secret}
      </#if>


</#if>
